let currentLang = 'en';

function applyLanguage(lang) {
  currentLang = lang;
  const dict = I18N[lang];
  if (!dict) return;

  // Text content
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (dict[key]) el.textContent = dict[key];
  });

  // Placeholders
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    if (dict[key]) el.placeholder = dict[key];
  });

  // Hide splash subtitle if empty
  const splashSub = document.querySelector('.splash-subtitle');
  if (splashSub) splashSub.style.display = splashSub.textContent ? '' : 'none';

  // Update calendar month label
  updateCalendarMonthLabel();

  // Update language label in settings
  const langLabel = document.getElementById('current-lang-label');
  if (langLabel) langLabel.textContent = lang === 'zh' ? '中文' : 'English';
}
